SELECT 
  FROM emp.tn_emp_oprtr_cnct c
 WHERE c.emp_plan_id = #{empPlanId}
   AND c.cnct_sn     = #{sn}
   AND NOW() BETWEEN c.use_bgng_dt AND c.use_end_dt

SELECT COALESCE(MAX(cnct_sn), 0) + 1
  FROM emp.tn_emp_oprtr_cnct
 WHERE emp_plan_id = #{empPlanId}

SELECT COUNT(*)
  FROM emp.tn_emp_oprtr_cnct
 WHERE emp_plan_id = #{empPlanId}
   AND cnct_se_cd  = #{cnctSeCd}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt

mapper.update:
UPDATE emp.tn_emp_oprtr_cnct
   SET cnct_se_cd       = #{cnctSeCd},
       user_nm          = #{userNm},
       mblphn_no        = #{mblphnNo},
       eml_addr         = #{emlAddr},
       last_chg_dt      = NOW(),
       last_chg_user_id = #{lastChgUserId}
 WHERE emp_plan_id = #{empPlanId}
   AND cnct_sn     = #{cnctSn}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt

UPDATE emp.tn_emp_oprtr_cnct
   SET use_end_dt       = NOW() - INTERVAL '1 minute',
       last_chg_dt      = NOW(),
       last_chg_user_id = #{userId}
 WHERE emp_plan_id = #{empPlanId}
   AND cnct_sn     = #{sn}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt
